body.script:
test(function() {
  assert_not_background_color('first', RED, 'First paragraph should not be red');
  assert_background_color('t1', LIME, 'Second paragraph should be green');
  assert_background_color('t2', LIME, 'Third paragraph should be green');
  assert_background_color('t3', LIME, 'Fourth paragraph should be green');
}, 'Indirect adjacent combinator');
